import java.util.HashMap;

class TwoSum {
    private HashMap<Integer, Integer> nums;

    public TwoSum() {
        nums = new HashMap<>();
    }

    public void add(int number) {
        nums.put(number, nums.getOrDefault(number, 0) + 1);
    }

    public boolean find(int value) {
        for (Integer i : nums.keySet()) {
            int complement = value - i;
            if (nums.containsKey(complement)) {
                if (i != complement || nums.get(i) > 1) {
                    return true;
                }
            }
        }
        return false;
    }
}
